public class TestCase {
    // Private fields (encapsulation)
    private String testId;
    private String testName;
    private String status;
    private int executionTime;

    // Constructor to initialize all fields
    public TestCase(String testId, String testName, String status, int executionTime) {
        this.testId = testId;
        this.testName = testName;
        this.status = status;
        this.executionTime = executionTime;
    }

    // Getter methods
    public String getTestId() {
        return testId;
    }

    public String getTestName() {
        return testName;
    }

    public String getStatus() {
        return status;
    }

    public int getExecutionTime() {
        return executionTime;
    }

    // Method to check if test passed
    public boolean isPass() {
        return "PASS".equals(status);
    }

    // Method to get formatted test details
    public String getDetails() {
        return String.format("Test ID: %s, Name: %s, Status: %s, Execution Time: %d ms",
                           testId, testName, status, executionTime);
    }

    public static void main(String[] args) {
        // Create test case objects
        TestCase test1 = new TestCase("TC001", "Login Test", "PASS", 150);
        TestCase test2 = new TestCase("TC002", "Logout Test", "FAIL", 200);

        System.out.println(test1.getDetails());
        System.out.println("Test passed: " + test1.isPass());

        System.out.println(test2.getDetails());
        System.out.println("Test passed: " + test2.isPass());
    }
}
